# Write patch.json
patch_path = Path(__file__).parent / "data" / "patch.json"
patch_path.parent.mkdir(parents=True, exist_ok=True)

with open(patch_path, "w", encoding="utf-8") as f:
    json.dump(DATA, f, indent=2, ensure_ascii=False)

print(f"Wrote {len(DATA)} concepts to {patch_path}")
for cid, opts in DATA.items():
    print(f"  {cid}: {len(opts)} options — first: \"{opts[0]['name']}\"")
